    const [debounced, setDebounced] = useState(value);
    const [pending, setPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // If nothing changed, there's nothing to settle.
        if (value === debounced) {
            setPending(false);
            return;
        }

        setPending(true);
        timeoutRef.current = setTimeout(() => {
            setDebounced(value);
            setPending(false);
        }, delay);

        // Cleanup: clear the pending timeout on value change OR unmount.
        // This prevents memory leaks / state updates after unmount.
        return () => {
            clearTimeout(timeoutRef.current);
        };
